from time import *
import math
from physical import *
from gpio import *
from environment import Environment
from ioeclient import IoEClient


WATERLEVEL_RATE = -0.5 # 0.5 cm per second        # var WATERLEVEL_RATE
VOLUME_AT_RATE = 100000/2.5        # var VOLUME_AT_RATE
MAX_RATE = -1.e6        # var MAX_RATE

state = 0 # 0 off, 1 on        # var state


def setup ():

    IoEClient.setup({
        "type": "Water Drain",
        "states": [{
            "name": "Status",
            "type": "bool",
            "controllable": True
        }]
    })

    IoEClient.onInputReceive = lambda rinput: processData(rinput, True)

    def on_event_detect():
        processData(customRead(0), False)
    add_event_detect(0, on_event_detect)

    setState(state)



def mouseEvent (pressed, x, y, firstPress):
    if firstPress:
        setState(( 0  if state  else 1 ) )



def processData (data, bIsRemote):
    if len(data) <= 0:
        return
    setState(int(data))



def setState (newState):
    global state
    state = newState
    analogWrite(A1, state)
    customWrite(0, state)
    IoEClient.reportStates(state)
    setDeviceProperty(getName(), "state", state)
    updateEnvironment()



def updateEnvironment ():
    if state == 1:
        volumeRatio = VOLUME_AT_RATE / Environment.getVolume()        # var volumeRatio
        if Environment.get("Water Level") >= 0:
            Environment.setContribution("Water Level", WATERLEVEL_RATE * volumeRatio, MAX_RATE, True)
        else:
            Environment.setContribution("Water Level", 0, 0, True)
    else:
        Environment.setContribution("Water Level", 0, 0, True)




if __name__ == "__main__":
    setup()
    while True:
        #loop()
        sleep(0)

var WATERLEVEL_RATE = -0.5;	// 0.5 cm per second
var VOLUME_AT_RATE = 100000;

var state = 0;	// 0 off, 1 on

function setup() {
	
	IoEClient.setup({
		type: "Water Drain",
		states: [
		{
			name: "Status",
			type: "bool",
			controllable: true
		}			
		]
	});
	
	IoEClient.onInputReceive = function(input) {
		processData(input, true);
	};
	
	attachInterrupt(0, function() {
		processData(customRead(0), false);
	});
	
	state = restoreProperty("state", 0);
	setState(state);
}

function restoreProperty(propertyName, defaultValue)
{
	var value = getDeviceProperty(getName(), propertyName);
	if ( !(value === "" || value == "undefined") ){
		if ( typeof(defaultValue) == "number" )
			value = Number(value);
		
		setDeviceProperty(getName(), propertyName, value);
		return value;
	}
	
	return defaultValue;
}

function mouseEvent(pressed, x, y, firstPress) {
	if (firstPress)
		setState(state ? 0 : 1);
}

function processData(data, bIsRemote) {
	if ( data.length <= 0  )
		return;
	setState(parseInt(data));
}

function setState(newState)
{
	state = newState;
	analogWrite(A1, state);
	customWrite(0, state);
	IoEClient.reportStates(state);
	setDeviceProperty(getName(), "state", state);
	updateEnvironment();
}

function updateEnvironment()
{
	if ( state == 1){
		var volumeRatio = VOLUME_AT_RATE / Environment.getVolume();
		if ( Environment.get("Water Level") >= 0 )
			Environment.setContribution("Water Level", WATERLEVEL_RATE*volumeRatio);
		else
			Environment.setContribution("Water Level", 0);	
	}
	else
	{
		Environment.setContribution("Water Level", 0);
	}
}

